import fs from "node:fs";
import path from "node:path";

const root = process.cwd();
const metadataDir = path.join(root, "metadata");

const WARNING_HEADER =
  "<!-- Generated by scripts/core/generate-repo-indexes.mjs from metadata/*.json. Do not edit by hand. -->";

function readJson(rel) {
  return JSON.parse(fs.readFileSync(path.join(root, rel), "utf8"));
}

function exists(rel) {
  return fs.existsSync(path.join(root, rel));
}

function readDir(rel) {
  try {
    return fs.readdirSync(path.join(root, rel), { withFileTypes: true });
  } catch {
    return [];
  }
}

function sorted(iterable, keyFn) {
  const arr = [...iterable];
  if (keyFn) {
    return arr.sort((a, b) => String(keyFn(a)).localeCompare(String(keyFn(b))));
  }
  return arr.sort((a, b) => {
    const va = a.name !== undefined ? a.name : String(a);
    const vb = b.name !== undefined ? b.name : String(b);
    return String(va).localeCompare(String(vb));
  });
}

const modules = readJson("metadata/modules.json");
const tasks = readJson("metadata/tasks.json");
const contractsData = readJson("metadata/contracts.json");
const catalogData = readJson("metadata/catalog.json");

function writeIndex(relPath, content) {
  const abs = path.join(root, relPath);
  const dir = path.dirname(abs);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
  fs.writeFileSync(abs, content, "utf8");
}

function generateDocsIndex() {
  const lines = [WARNING_HEADER, "", "# Documentation Index", "", ""];

  const entries = sorted(readDir("docs"));
  const dirs = entries.filter((e) => e.isDirectory());
  const files = entries.filter((e) => e.isFile() && e.name.endsWith(".md") && e.name !== "INDEX.md");

  if (dirs.length > 0) {
    lines.push("## Sections");
    lines.push("");
    for (const d of sorted(dirs)) {
      const label = d.name.replace(/-/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
      lines.push(`- [${label}](docs/${d.name}/)`);
    }
    lines.push("");
  }

  if (files.length > 0) {
    lines.push("## Documents");
    lines.push("");
    for (const f of sorted(files)) {
      const name = f.name.replace(/\.md$/, "").replace(/-/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
      lines.push(`- [${name}](docs/${f.name})`);
    }
    lines.push("");
  }

  const hasModules = (modules.modules || []).length > 0;
  if (hasModules) {
    lines.push("## Modules");
    lines.push("");
    lines.push(`See [docs/modules/INDEX.md](docs/modules/INDEX.md) for module documentation.`);
    lines.push("");
  }

  const hasContracts = (contractsData.contracts || []).length > 0;
  if (hasContracts) {
    lines.push("## Contracts");
    lines.push("");
    lines.push(`See [docs/architecture/contracts/](docs/architecture/contracts/) for contract documentation.`);
    lines.push("");
  }

  return lines.join("\n");
}

function generateModulesIndex() {
  const lines = [WARNING_HEADER, "", "# Module Documentation Index", "", ""];
  lines.push("Source: `metadata/modules.json`", "");
  lines.push("| Module | Side | Type | Status | Path |");
  lines.push("|--------|------|------|--------|------|");

  const sortedModules = sorted(modules.modules || [], (m) => `${m.side}:${m.name}`);
  for (const mod of sortedModules) {
    const manifest = exists(mod.manifestPath) ? "✓" : "—";
    lines.push(`| ${mod.name} | ${mod.side} | ${mod.type} | ${manifest} | \`${mod.path}\` |`);
  }

  lines.push("");
  return lines.join("\n");
}

function generateTasksIndex() {
  const lines = [WARNING_HEADER, "", "# Task Documentation Index", "", ""];
  lines.push("Source: `metadata/tasks.json`", "");
  lines.push("| Task | Type | Path |");
  lines.push("|------|------|------|");

  const sortedTasks = sorted(tasks.tasks || [], (t) => t.name);
  for (const t of sortedTasks) {
    lines.push(`| ${t.name} | ${t.type} | \`${t.path}\` |`);
  }

  lines.push("");
  return lines.join("\n");
}

function generateScriptsTasksIndex() {
  const lines = [WARNING_HEADER, "", "# Scripts — Task Index", "", ""];

  const entries = readDir("scripts/tasks");
  const taskDirs = entries.filter((e) => e.isDirectory());

  lines.push("Source: \`scripts/tasks/\` directories", "");
  lines.push("| Task | Path |");
  lines.push("|------|------|");

  for (const d of sorted(taskDirs)) {
    lines.push(`| ${d.name} | \`scripts/tasks/${d.name}/\` |`);
  }

  lines.push("");
  return lines.join("\n");
}

function generateWorkLogTasksIndex() {
  const lines = [WARNING_HEADER, "", "# Work Log — Task Index", "", ""];

  const entries = readDir("work-log/tasks");
  const taskDirs = entries.filter((e) => e.isDirectory());

  lines.push("Source: \`work-log/tasks/\` directories", "");
  lines.push("| Task | Path |");
  lines.push("|------|------|");

  for (const d of sorted(taskDirs)) {
    lines.push(`| ${d.name} | \`work-log/tasks/${d.name}/\` |`);
  }

  lines.push("");
  return lines.join("\n");
}

const indexSpecs = [
  ["docs/INDEX.md", generateDocsIndex],
  ["docs/modules/INDEX.md", generateModulesIndex],
  ["docs/tasks/INDEX.md", generateTasksIndex],
  ["scripts/tasks/INDEX.md", generateScriptsTasksIndex],
  ["work-log/tasks/INDEX.md", generateWorkLogTasksIndex],
];

for (const [relPath, generatorFn] of indexSpecs) {
  const content = generatorFn();
  writeIndex(relPath, content);
  console.log(`Generated: ${relPath}`);
}

console.log("\nDone. All generated indexes are deterministic.");
